def max_sum_increasing_subsequence(arr):
    n = len(arr)
    if n == 0:
        return 0

    # dp[i] will store the maximum sum of an increasing subsequence
    # ending at index i
    dp = list(arr)

    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j]:
                dp[i] = max(dp[i], dp[j] + arr[i])

    return max(dp)
